ont-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.mex-log-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px}\n.mex-log-item{display:flex;gap:16px;align-items:flex-start;background:#fff;border-radius:12px;padding:20px}\n.mex-log-icon{width:40px;height:40px;border-radius:8px;background:rgba(109,40,217,0.1);display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.mex-log-icon svg{stroke:#6d28d9}\n.mex-log-item-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#000864;margin-bottom:2px}\n.mex-log-item-value{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#333;line-height:1.5}\n\n.et_pb_section .mex-log-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .mex-log-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .mex-log-item-label,.et_pb_section .mex-log-item-value{-webkit-font-smoothing:auto !important}\n\n@media(max-width:768px){\n  .mex-log-grid{grid-template-columns:1fr}\n  .mex-log-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.mex-log-section *{transition:none !important}}\n/* === REGISTRATION CTA === */\n.mex-reg-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:80px 24px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.mex-reg-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.mex-reg-section>*{position:relative;z-index:2}\n.mex-reg-section h2{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#fff;margin:0 0 16px;padding:0}\n.mex-reg-meta{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.85);margin:0 0 32px;padding:0}\n.mex-reg-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#fff;background:#6d28d9;padding:20px 48px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(109,40,217,0.4)}\n.mex-reg-cta:hover{background:rgb(138,83,225);transform:translateY(-2px);box-shadow:0 8px 24px rgba(109,40,217,0.3)}\n.mex-reg-secondary{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-top:24px;padding:0}\n.mex-reg-secondary a{color:#fff;text-decoration:underline;transition:color 0.3s ease}\n.mex-reg-secondary a:hover{color:#fff}\n\n.et_pb_section .mex-reg-section h2{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .mex-reg-cta{-webkit-font-smoothing:auto !important;line-height:28.8px !important}\n.et_pb_section .mex-reg-meta,.et_pb_section .mex-reg-secondary{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .mex-reg-section h2{font-size:32px}\n  .mex-reg-cta{width:100%;justify-content:center;padding:16px 32px;font-size:16px}\n}\n@media(prefers-reduced-motion:reduce){.mex-reg-section *{transition:none !important}}\n/* === RELATED EVENTS === */\n.mex-rel-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.mex-rel-inner{max-width:1100px;margin:0 auto}\n.mex-rel-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#6d28d9;margin-bottom:16px}\n.mex-rel-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.mex-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.mex-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.mex-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.mex-rel-card-border{height:4px}\n.mex-rel-card-body{padding:28px}\n.mex-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.mex-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.mex-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.mex-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.mex-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.mex-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.mex-rel-link:hover{opacity:0.8}\n\n.et_pb_section .mex-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .mex-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .mex-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .mex-rel-grid{grid-template-columns:1fr}\n  .mex-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.mex-rel-card{transition:none !important}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mex-hero-section">\n  <div class="mex-hero-superd" aria-hidden="true"></div>\n  <a href="/news/" class="mex-hero-back">\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n    Back to News &amp; Events\n  </a>\n  <span class="mex-hero-badge">Trade Show</span>\n  <h1>Manufacturing Expo Thailand 2026</h1>\n  <p class="mex-hero-subtitle">Visit us at Booth A12. Live demos of ERP, MES, WMS, and AIoT solutions. Meet our Thai team and see the full manufacturing intelligence stack in action.</p>\n\n  <div class="mex-hero-facts">\n    \n      <div class="mex-hero-fact">\n        <div class="mex-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n        </div>\n        <div class="mex-hero-fact-value">May 20–22, 2026</div>\n        <div class="mex-hero-fact-label">Wednesday–Friday</div>\n      </div>\n\n      <div class="mex-hero-fact">\n        <div class="mex-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n        </div>\n        <div class="mex-hero-fact-value">10:00 – 18:00</div>\n        <div class="mex-hero-fact-label">Daily</div>\n      </div>\n\n      <div class="mex-hero-fact">\n        <div class="mex-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n        </div>\n        <div class="mex-hero-fact-value">BITEC, Bangkok</div>\n        <div class="mex-hero-fact-label">Booth A12</div>\n      </div>\n\n      <div class="mex-hero-fact">\n        <div class="mex-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n        </div>\n        <div class="mex-hero-fact-value">Open Entry</div>\n        <div class="mex-hero-fact-label">No Registration Required</div>\n      </div>\n  </div>\n\n  <a href="#register" class="mex-hero-cta">\n    Book a 1-on-1 Meeting\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mex-prob-section">\n  <div class="mex-prob-inner">\n    <span class="mex-prob-label">Why Visit Our Booth</span>\n    <h2 class="mex-prob-title">Three Days to Explore the Full Manufacturing Intelligence Stack</h2>\n  </div>\n  <div class="mex-prob-body">\n    \n    <p>Trade shows let you compare vendors side by side — but most booths show generic slides, recycled marketing decks, and scripted pitches that tell you nothing about how the software actually works on a Thai factory floor.</p>\n\n    <p>At the DigiWin booth, you\'ll see <strong>live software running with real Thai factory data</strong>. Not screenshots. Not PowerPoints. Actual ERP transactions, MES dashboards updating in real time, warehouse scanning workflows you can try yourself, and sensor data streaming from machines to analytics dashboards.</p>\n\n    <p>Bring your specific questions — our Thai consultants speak your language and understand your industry. Whether you\'re evaluating ERP for the first time, looking to add MES or WMS to your existing system, or exploring how AIoT can connect your shop floor machines, this is the fastest way to understand what DigiWin can do for your factory.</p>\n    \n    <div class="mex-prob-data-card">\n      <div class="mex-prob-data-content">\n        <div class="mex-prob-data-number">Booth A12</div>\n        <div class="mex-prob-data-label">Hall 1, BITEC Bangkok — look for the blue DigiWin banner</div>\n      </div>\n    </div>\n    \n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="mex-out-section">\n  <div class="mex-out-inner">\n    <span class="mex-out-label">What You\'ll See</span>\n    <h2 class="mex-out-title">Four Live Demos Running Throughout the Show</h2>\n    <div class="mex-out-grid">\n      \n    <div class="mex-out-card">\n      <div class="mex-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M3 3h18v18H3V3z"/><path d="M3 9h18M9 21V9"/></svg>\n      </div>\n      <h3>Live ERP Demo</h3>\n      <p>T100 running with full Thai localization, BOI reporting, and Thai Revenue Department compliance — the exact configuration deployed in Thai factories today.</p>\n    </div>\n\n    <div class="mex-out-card">\n      <div class="mex-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M2 20h20M6 20V10l4-6h4l4 6v10"/><path d="M6 14h12"/></svg>\n      </div>\n      <h3>MES Dashboard</h3>\n      <p>Real-time production monitoring with actual factory data flowing live. See OEE calculations, production order tracking, and quality metrics updating as you watch.</p>\n    </div>\n\n    <div class="mex-out-card">\n      <div class="mex-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><path d="M3.27 6.96L12 12.01l8.73-5.05M12 22.08V12"/></svg>\n      </div>\n      <h3>WMS with Barcode Scanning</h3>\n      <p>Pick, pack, and ship workflow demonstration. Try the handheld scanner yourself and see how warehouse operations flow from receiving to dispatch.</p>\n    </div>\n\n    <div class="mex-out-card">\n      <div class="mex-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><circle cx="12" cy="12" r="3"/><path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4"/></svg>\n      </div>\n      <h3>AIoT Machine Connectivity</h3>\n      <p>See sensor data flowing from machines to analytics dashboards in real time. Understand how IoT connects your shop floor equipment to actionable intelligence.</p>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module"