ewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            Bangkok, Thailand\n          </div>\n        </div>\n        <a href="/news/events/boi-compliance-workshop/" class="mex-rel-link" style="color:#15803d">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="mex-rel-card">\n      <div class="mex-rel-card-border" style="background:#b45309"></div>\n      <div class="mex-rel-card-body">\n        <span class="mex-rel-badge" style="color:#b45309;background:rgba(180,83,9,0.12)">Factory Visit</span>\n        <h3>Live Factory Tour: See DigiWin MES in Action</h3>\n        <div class="mex-rel-meta">\n          <div class="mex-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            May 8, 2026\n          </div>\n          <div class="mex-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            EEC Industrial Zone\n          </div>\n        </div>\n        <a href="/news/events/factory-tour-mes/" class="mex-rel-link" style="color:#b45309">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n\n    <div class="mex-rel-card">\n      <div class="mex-rel-card-border" style="background:#0369a1"></div>\n      <div class="mex-rel-card-body">\n        <span class="mex-rel-badge" style="color:#0369a1;background:rgba(3,105,161,0.12)">Seminar</span>\n        <h3>Production Transparency: From Paper Reports to Real-Time Dashboards</h3>\n        <div class="mex-rel-meta">\n          <div class="mex-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n            April 10, 2026\n          </div>\n          <div class="mex-rel-meta-item">\n            <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="14" height="14"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n            Bangkok, Thailand\n          </div>\n        </div>\n        <a href="/news/events/production-transparency-seminar/" class="mex-rel-link" style="color:#0369a1">Learn More\n          <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n        </a>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
